import java.lang.reflect.Method;
import java.util.HashMap;
import java.util.Map;

public class EventBus {
    private final Map<String, Object> handlers = new HashMap<>();

    public void register(String eventType, Object handler) {
        handlers.put(eventType, handler);
    }

    public void publish(String eventType, Object payload) throws Exception {
        Object handler = handlers.get(eventType);
        if (handler != null) {
            Method m = handler.getClass().getDeclaredMethod("on" + eventType, Object.class);
            m.invoke(handler, payload);
        }
    }
}
EOF
